import pytest

def test_create_benefit_missing_mandatory_field_returns_400(manager_token, api_client):
    payload = {
        "type": "HEALTH",
        "description": "No name provided",
        "effective_date": "2024-01-01"
    }
    response = api_client.post(
        "/api/benefits",
        json=payload,
        headers={"Authorization": f"Bearer {manager_token}"}
    )
    assert response.status_code == 400, f"Expected 400, got {response.status_code}"
    body = response.json()
    errors = body.get("errors") or body.get("detail") or ""
    assert "name" in str(errors).lower(), "Validation error must reference missing 'name' field"

